import { PublicActionPage } from '@domain/publicActionPage';
import { useFormContext } from 'react-hook-form';
import {
  FormEmploymentControl,
  FormEmploymentControlProps,
} from '../../../../../../components/EmploymentControl/FormEmploymentControl';

export type EmploymentFieldProps = FormEmploymentControlProps & {
  actionPage?: PublicActionPage;
  displayEmployment?: boolean;
  isPreview?: boolean;
};

export const Employment = ({
  displayEmployment = true,
  isPreview = false,
  ...formEmploymentControlProps
}: EmploymentFieldProps) => {
  const { watch } = useFormContext();
  const donorProfile = isPreview ? null : watch('donorProfile');

  const nonEmployedOccupationOptions = ['unemployed', 'homemaker', 'retired', 'student'];

  if (donorProfile) {
    const { employerCity, employerCountry, employerLine1, employerPostalCode, employerRegion } =
      donorProfile;

    const hasAddress =
      !!employerCity &&
      !!employerCountry &&
      !!employerLine1 &&
      !!employerPostalCode &&
      !!employerRegion;

    const isOccupationValid =
      donorProfile.occupation &&
      (nonEmployedOccupationOptions.includes(donorProfile.occupation) ||
        !formEmploymentControlProps.occupationOptions?.length ||
        formEmploymentControlProps.occupationOptions.includes(donorProfile.occupation));

    if (isOccupationValid && donorProfile.employer) {
      if (formEmploymentControlProps.includeEmployerAddress && displayEmployment && !hasAddress) {
        return (
          <FormEmploymentControl
            {...formEmploymentControlProps}
            includeEmployerName={false}
            includeOccupation={false}
            showRadio={false}
          />
        );
      } else {
        return null;
      }
    } else if (isOccupationValid || donorProfile.employer) {
      return (
        <FormEmploymentControl
          {...formEmploymentControlProps}
          includeEmployerAddress={!hasAddress && formEmploymentControlProps.includeEmployerAddress}
          includeEmployerName={
            !donorProfile.employer && formEmploymentControlProps.includeEmployerName
          }
          includeOccupation={!isOccupationValid && formEmploymentControlProps.includeOccupation}
          showRadio={false}
        />
      );
    }
  }

  return displayEmployment ? <FormEmploymentControl {...formEmploymentControlProps} /> : null;
};

